module adder_pipe_64bit(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [63:0] result,
    output o_en
);

reg [63:0] reg_adda, reg_addb;
reg [63:0] sum;
reg carry;
reg [1:0] stage;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        reg_adda <= 0;
        reg_addb <= 0;
        sum <= 0;
        carry <= 0;
        stage <= 0;
    end
    else if (i_en) begin
        reg_adda <= adda;
        reg_addb <= addb;
        stage <= 1;
    end
    else if (stage == 1) begin
        {carry, sum} <= reg_adda + reg_addb;
        stage <= 2;
    end
    else if (stage == 2) begin
        stage <= 3;
    end
    else if (stage == 3) begin
        stage <= 0;
    end
end

assign result = sum;
assign o_en = (stage == 3);

endmodule
